
/* ========== 外层容器 ========== */
.phone-outer {
  width: 100%;
  display: flex;
  justify-content: center;
  padding: 16px 8px;
}

/* ========== 手机边框外壳 ========== */
.phone-frame {
  width: 100%;
  max-width: 390px;
  aspect-ratio: 9 / 19;
  background: #1a1a2e;
  border-radius: 40px;
  padding: 12px;
  box-shadow:
    0 0 0 3px #2d2d44,
    0 0 0 6px #1a1a2e,
    0 0 0 8px #2d2d44,
    0 12px 40px rgba(0, 0, 0, 0.5);
  display: flex;
  flex-direction: column;
}

/* ========== 内部屏幕 ========== */
.phone-screen {
  flex: 1;
  background: linear-gradient(180deg, #f5f5f7 0%, #e8e8ed 100%);
  border-radius: 30px;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

/* ========== 刘海区域 ========== */
.phone-notch-area {
  display: flex;
  justify-content: center;
  height: 28px;
  flex-shrink: 0;
}

.phone-notch {
  width: 120px;
  height: 26px;
  background: #1a1a2e;
  border-radius: 0 0 18px 18px;
}

/* ========== 顶部状态栏 ========== */
.phone-status-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 4px 28px 6px;
  font-size: 12px;
  font-weight: 600;
  color: #1a1a2e;
  flex-shrink: 0;
}

.status-time {
  font-weight: 700;
}

.status-icons {
  display: flex;
  gap: 4px;
  font-size: 10px;
}

/* ========== 聊天头部 ========== */
.chat-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 6px 20px 8px;
  border-bottom: 1px solid rgba(0, 0, 0, 0.08);
  flex-shrink: 0;
}

.chat-header-left {
  display: flex;
  align-items: center;
  gap: 10px;
}

.back-btn {
  font-size: 14px;
  color: #555;
  cursor: pointer;
}

.avatar {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background-color: #e0e0e0;
  background-size: cover;
  background-position: center;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.avatar-fallback {
  font-size: 16px;
  font-weight: 700;
  color: #666;
}

.chat-header-info {
  display: flex;
  flex-direction: column;
  min-width: 0;
}

.chat-header-name {
  font-size: 15px;
  font-weight: 700;
  color: #1a1a2e;
  line-height: 1.2;
}

.chat-header-status {
  font-size: 11px;
  color: #4caf50;
  line-height: 1.2;
}

.chat-header-right {
  color: #555;
  font-size: 16px;
  cursor: pointer;
}

/* ========== 聊天消息区域 ========== */
.chat-messages {
  flex: 1;
  overflow-y: auto;
  padding: 8px 16px;
  display: flex;
  flex-direction: column;
  gap: 6px;
  min-height: 0;

  &::-webkit-scrollbar {
    width: 3px;
  }

  &::-webkit-scrollbar-thumb {
    background: rgba(0, 0, 0, 0.15);
    border-radius: 2px;
  }
}

.chat-time-label {
  text-align: center;
  font-size: 11px;
  color: #999;
  padding: 6px 0;
}

/* ========== 消息气泡 ========== */
.message-row {
  display: flex;
  align-items: flex-start;
  gap: 6px;
  max-width: 85%;
}

.msg-left {
  align-self: flex-start;
}

.msg-right {
  align-self: flex-end;
  flex-direction: row-reverse;
}

.msg-avatar {
  width: 28px;
  height: 28px;
  border-radius: 50%;
  background-color: #ddd;
  background-size: cover;
  background-position: center;
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
}

.msg-bubble {
  padding: 8px 12px;
  border-radius: 16px;
  font-size: 13px;
  line-height: 1.45;
  word-break: break-word;
  white-space: pre-wrap;
}

.bubble-char {
  background: #ffffff;
  color: #333;
  border-top-left-radius: 4px;
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.06);
}

.bubble-user {
  background: #4a90d9;
  color: #fff;
  border-top-right-radius: 4px;
}

/* ========== 状态卡片 ========== */
.status-card-wrapper {
  align-self: center;
  width: 100%;
  margin: 8px 0;
}

.status-card {
  background: #ffffff;
  border-radius: 16px;
  padding: 12px 14px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
  border: 1px solid rgba(0, 0, 0, 0.06);
}

.status-card-header {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 14px;
  font-weight: 700;
  color: #1a1a2e;
  margin-bottom: 10px;
  padding-bottom: 8px;
  border-bottom: 1px solid rgba(0, 0, 0, 0.06);

  i {
    color: #4a90d9;
  }
}

.stat-row {
  display: grid;
  grid-template-columns: 60px 42px 1fr;
  align-items: center;
  gap: 8px;
  margin-bottom: 8px;
  font-size: 12px;
}

.stat-label {
  color: #666;
  font-weight: 600;

  i {
    width: 14px;
    text-align: center;
    font-size: 11px;
  }

  .fa-heart {
    color: #e74c3c;
  }

  .fa-star {
    color: #f39c12;
  }

  .fa-running {
    color: #2ecc71;
  }
}

.stat-value {
  color: #333;
  font-weight: 700;
  text-align: right;
  font-variant-numeric: tabular-nums;
}

.stat-bar {
  height: 8px;
  background: #e9ecef;
  border-radius: 4px;
  overflow: hidden;
}

.stat-bar-fill {
  height: 100%;
  border-radius: 4px;
  transition: width 0.6s ease;
}

.hp-fill {
  background: linear-gradient(90deg, #e74c3c, #ff6b6b);
}

.mp-fill {
  background: linear-gradient(90deg, #3498db, #5dade2);
}

.stamina-fill {
  background: linear-gradient(90deg, #2ecc71, #58d68d);
}

/* ========== 状态标签 ========== */
.stat-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-top: 10px;
}

.tag {
  font-size: 11px;
  padding: 3px 8px;
  border-radius: 10px;
  font-weight: 600;
}

.tag-normal {
  background: #e8f5e9;
  color: #2e7d32;
}

.tag-buff {
  background: #e3f2fd;
  color: #1565c0;
}

.tag-debuff {
  background: #fce4ec;
  color: #c62828;
}

.tag-shield {
  background: #fff8e1;
  color: #f57f17;
}

/* ========== 额外属性 ========== */
.stat-extra {
  display: flex;
  justify-content: space-around;
  margin-top: 10px;
  padding-top: 10px;
  border-top: 1px solid rgba(0, 0, 0, 0.06);
}

.extra-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.extra-icon {
  font-size: 16px;
}

.extra-label {
  font-size: 10px;
  color: #999;
}

.extra-value {
  font-size: 14px;
  font-weight: 700;
  color: #1a1a2e;
}

/* ========== 底部输入区域 ========== */
.chat-input-area {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 20px 6px;
  border-top: 1px solid rgba(0, 0, 0, 0.08);
  flex-shrink: 0;
}

.input-plus {
  font-size: 22px;
  color: #888;
  cursor: pointer;
}

.input-field {
  flex: 1;
  background: #ffffff;
  border: 1px solid rgba(0, 0, 0, 0.12);
  border-radius: 20px;
  padding: 8px 14px;
}

.input-placeholder {
  font-size: 13px;
  color: #bbb;
}

.input-emoji {
  font-size: 18px;
  color: #888;
  cursor: pointer;
}

/* ========== 底部横条 ========== */
.phone-home-bar {
  display: flex;
  justify-content: center;
  padding: 6px 0 2px;
  flex-shrink: 0;

  &::after {
    content: '';
    width: 100px;
    height: 4px;
    background: rgba(0, 0, 0, 0.2);
    border-radius: 2px;
  }
}
